SELECT COUNT(*)
FROM REPORT
WHERE REPORTER_NO = #{reporterNo}
AND TARGET_TYPE = #{targetType}
AND TARGET_NO = #{targetNo}

SELECT r.NO, r.REPORTER_NO, r.TARGET_TYPE, r.TARGET_NO, r.REASON, r.CONTENT, r.STATUS, r.REGDATE AS reg_date, r.UPDATE_DATE AS update_date, m.MEMBER_ID AS reporter_id, m.NAME AS reporter_name, b.TITLE AS target_title FROM REPORT r JOIN MEMBER m ON r.REPORTER_NO = m.NO LEFT JOIN BOARD b ON r.TARGET_TYPE = 'BOARD' AND r.TARGET_NO = b.NO WHERE 1 = 1
AND r.STATUS = #{searchStatus}
AND r.TARGET_TYPE = #{searchTargetType}
AND m.MEMBER_ID = #{keyword}
AND b.TITLE LIKE '%' || #{keyword} || '%'
ORDER BY r.NO DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*) FROM REPORT r JOIN MEMBER m ON r.REPORTER_NO = m.NO LEFT JOIN BOARD b ON r.TARGET_TYPE = 'BOARD' AND r.TARGET_NO = b.NO WHERE 1 = 1
AND r.STATUS = #{searchStatus}
AND r.TARGET_TYPE = #{searchTargetType}
AND m.MEMBER_ID = #{keyword}
AND b.TITLE LIKE '%' || #{keyword} || '%'
